(function () {
    if (getConfig()?.user?.role != 'Pencacah' && !getValue('kodepos')) return true
    
    function transformToObjects(input) {
        const keys = Object.keys(input);
        const length = input[keys[0]]?.length || 0;

        return Array.from({ length }, (_, i) => {
            const obj = {};
            keys.forEach(key => {
                obj[key] = input[key][i] ?? "";
            });
            return obj;
        });
    }

    const arr = getPrincipalCollection(["data9"]);

    return transformToObjects(arr).some(row =>
        String(row.data9 || "").trim() !== ""
    );
})()

