try {
    const maskNama = (nama = "") =>
      nama
        .trim()
        .split(/\s+/)
        .map(kata => {
          if (kata.length <= 2) return kata;
          return (
            kata[0] +
            "*".repeat(kata.length - 2) +
            kata[kata.length - 1]
          );
        })
        .join(" ");
    
  const rowIndex = getRowIndex(0);

