// Ambil row index sekali saja
const rowIndex = getRowIndex(0);

// Reset result dulu
setValue(`result_gen_ai#${rowIndex}`, "");

// Helper ambil value array option
const getOptionValue = (field) =>
  getValue(`${field}#${rowIndex}`)?.[0]?.value ?? "";

const getOptionLabel = (field) =>
  getValue(`${field}#${rowIndex}`)?.[0]?.label ?? "";

// Ambil semua input
const jenis = getOptionValue("jenis_usaha") ?? "";
const keg = getValue(`keg_utama#${rowIndex}`) ?? "";
const produk_sendiri = getOptionValue("produk_sendiri");
const layanan_mamin = getOptionValue("layanan_mamin");
const keg_penjualan = getOptionValue("keg_penjualan");
const keg_jasa = getOptionValue("keg_jasa");
const lokasi = getOptionLabel("lokasi_usaha");
const input = getValue(`input#${rowIndex}`) ?? "";
const proses = getValue(`proses#${rowIndex}`) ?? "";
const produk = getValue(`produk#${rowIndex}`) ?? "";

// Bangun prompt
const promptParts = [];
if (keg) promptParts.push(`Usaha ${keg}`);
if (produk_sendiri === "1") promptParts.push("yang memproduksi barang sendiri");
if (layanan_mamin === "1") promptParts.push("dan menyediakan layanan makan minum");
if (keg_penjualan === "1") promptParts.push("yang menjual barang dari pihak lain");
if (keg_jasa === "1") promptParts.push("yang melakukan penjualan jasa");
if (lokasi) promptParts.push(`di ${lokasi}`);
if (input) promptParts.push(`dengan input ${input}`);
if (proses) promptParts.push(`melalui proses ${proses}`);
if (produk) promptParts.push(`dengan produk utama ${produk}`);

const panggil = promptParts.join(" ");

// Tentukan endpoint
const urlapi =
jenis =="6" ? "kbli-se2026-13_5" :
  layanan_mamin === "1" ? "kbli-se2026-13_3" :
  keg_penjualan === "1" ? "kbli-se2026-13_2" :
  keg_jasa === "1" ? "kbli-se2026-13_4" :
   keg_jasa === "2" ? "kbli-se2026-13_5" :
  "kbli-se2026-13_1";

const jumlah = 5;

// ?? Handle Promise atau non-Promise
const result = fetchExternalData(urlapi, {
  query: panggil,
  k: jumlah,
});

// Cek apakah Promise
if (result instanceof Promise) {
  result
    .then((response) => {
      setValue(`result_gen_ai#${rowIndex}`, JSON.stringify(response));
    })
    .catch((error) => {
      console.error("Error fetching data:", error);
    });
} else {
  // Kalau synchronous return
  setValue(`result_gen_ai#${rowIndex}`, JSON.stringify(result));
}

function getJsonKbli(jsonData) {
  try {

    const fixedString = jsonData
      .replace(/^"+|"+$/g, '') 
      .replace(/\\"/g, '"')    
      .replace(/\\'/g, "'")
      .replace(/\\"/g, '')
      .replace(/\\/g, '');
      
      //console.log(fixedString);
    
    const data = JSON.parse(fixedString);
//console.log(data);

    const resultArray = data.data.map((item, index) => ({
      value: String(index + 1) + item.kode,  // 1-digit index + 5-digit kode
      label: `[${item.kategori}] ${item.kode} ${item.judul}`,
    //   <br/><span style="color : #ff7f00;font-size:10px">${item.deskripsi}</span>
      description: item.deskripsi,
      open: false
    }));



     resultArray.push({
      value: '999999',
      label: 'Pilih dari Master KBLI',
      open: false,
      description: ''
    });

    return resultArray;
  } catch (error) {
    console.error('Error processing KBLI data:', error);

    return [{
      value: '999999',
      label: 'Pilih dari Master KBLI',
      open: false,
      description: ''
    }];
  }
}

