        });

      }

      // ==========================================
      // ERROR API
      // ==========================================

      else if (
        error ||
        message
      ) {

        hasil =
          "[4] Gagal mengambil data";

        html = createAlert({
          bg: "#FEF2F2",
          border: "#FCA5A5",
          color: "#B91C1C",
          title: "GAGAL MENGAMBIL DATA",
          message:
            message || error
        });

      }

      // ==========================================
      // FALLBACK
      // ==========================================

      else {

        hasil =
          "[4] Gagal mengambil data";

        html = createAlert({
          bg: "#FEF2F2",
          border: "#FCA5A5",
          color: "#B91C1C",
