            if (pendapatan_disetahunkan > LIMA_BELAS_MILIAR && String(r11d) == '2') {
                
                let skala = '';
                if (pendapatan_disetahunkan > LIMA_BELAS_MILIAR && pendapatan_disetahunkan <= LIMA_PULUH_MILIAR) {
                    skala = 'Menengah';
                } else if (pendapatan_disetahunkan > LIMA_PULUH_MILIAR) {
                    skala = 'Besar';
                }
            
                return {
                    nama_usaha: val('nama_usaha_edit') || val('nama_usaha'),
                    skala_unit_usaha: skala,
                    laporan_keuangan: val('lap_keuangan')?.[0]?.label || r11d
                };
            }
        },
        column: {
            nama_usaha: 'Nama Usaha/Perusahaan',
            skala_unit_usaha: 'Skala Unit Usaha',
            laporan_keuangan: 'Kepemilikan Laporan/Catatan Keuangan'
        }
    }
]

const initial_result = getValue('daftar_anomali') ?? {}

const result = {...initial_result}

const usaha_gabung = getValue('usaha_gabung') ?? [];

const cek_anomali = (rule) => {
    const daftar_anomali = []
    
    for (const usaha of usaha_gabung) {
        const index = usaha.value;
        const val = (dataKey) => getValue(dataKey + '#' + index)
        const anomali = rule.checkFn(val)
        if (anomali) daftar_anomali.push(anomali)
    }
    
    if (daftar_anomali.length) {
        result[rule.no] = {
            no: rule.no,
            message: rule.deskripsi,
            column: rule.column,
            daftar_anomali: daftar_anomali
        }
    } else {
        result[rule.no] = undefined
    }
}


const now = new Date()

if (!getValue('tanggal_anomali')) setValue('tanggal_anomali', now.toISOString())

const active_anomalies = Object.values(result).filter(n => !!n);

const anomali_solved = active_anomalies.every(anomali => {
    const catatan = getValue(`anomali_${anomali.no}_penjelasan`);

    return catatan && String(catatan).trim() !== ''; 
});

// Jika semua anomali sudah solved (atau tidak ada anomali) dan role adalah pencacah
if (anomali_solved && getConfig().user?.role.toLowerCase() === 'pencacah') {
    setValue('tanggal_selesai_anomali', now.toISOString());
} else if (!anomali_solved) {
    // atau catatan dihapus oleh user
    setValue('tanggal_selesai_anomali', null);
}

for (const rule of RULE_ANOMALI) { cek_anomali(rule) }

if (JSON.stringify(result) !== JSON.stringify(initial_result)) {
    setTimeout(() => setValue('daftar_anomali', {...result}))
}

window.renderAnomaliTable = (anomali, anomaliIndex = 0) => {
    if (!anomali?.daftar_anomali?.length) {
        return "";
    }

    const columns = Object.keys(anomali.column || {});
    const rows = anomali.daftar_anomali || [];

    const headerHtml = `
        <th style="
            padding:8px 12px;
            border:1px solid #d9e2ec;
            background:#f5f7fa;
            text-align:center;
            font-weight:600;
            width:60px;
        ">
            No
        </th>
        ${columns
            .map(key => `
                <th style="
                    padding:8px 12px;
                    border:1px solid #d9e2ec;
                    background:#f5f7fa;
                    text-align:left;
                    font-weight:600;
                ">
                    ${anomali.column[key]}
                </th>
            `)
            .join("")}
    `;

    const bodyHtml = rows
        .map((row, rowIndex) => {
            const cells = columns
                .map(key => {
                    let value = row[key];
                    return `
                        <td style="
                            padding:8px 12px;
                            border:1px solid #e2e8f0;
                        ">
                            ${value ?? "-"}
                        </td>
                    `;
                })
                .join("");

            return `
                <tr style="
                    background:${rowIndex % 2 === 0 ? "#fff" : "#fafbfc"};
                ">
                    <td style="
                        padding:8px;
                        text-align:center;
                        border:1px solid #e2e8f0;
                        font-weight:600;
                    ">
                        ${rowIndex + 1}
                    </td>

                    ${cells}
                </tr>
            `;
        })
        .join("");

    return `
        <div style="padding: 32px 0;">
            <hr style="
                border: none;
                border-top: 1px solid #dee2e6;
                margin: 0;
            ">
        </div>
        <div style="
            border:1px solid #d9e2ec;
            border-radius:8px;
            overflow:hidden;
            margin-bottom:20px;
            background:white;
        ">
            <div style="
                padding:16px;
                background:#fff8e1;
                border-bottom:1px solid #f0e0a0;
            ">
                <div style="
                    font-size:16px;
                    font-weight:700;
                    color:#7c5a00;
                    margin-bottom:10px;
                ">
                    Anomali #${anomali.no}
                </div>

                <div style="margin-bottom:6px;">
                    <b>Deskripsi:</b><br>
                    ${anomali.message}
                </div>

                <div>
                    <b>Jumlah Kasus:</b> ${rows.length}
                </div>
            </div>

            <div style="overflow:auto;">
                <table style="
                    width:100%;
                    border-collapse:collapse;
                    font-size:14px;
                ">
                    <thead>
                        <tr>
                            ${headerHtml}
                        </tr>
                    </thead>
                    <tbody>
                        ${bodyHtml}
                    </tbody>
                </table>
            </div>
        </div>
    `;
};
